class TestParseDimensionsResponse:
    def test_happy_path(self):
        response = json.dumps({
            "dimensions": [
                {"name": "clarity", "weight": 0.3, "score": 0.85, "description": "How clear"},
                {"name": "brevity", "weight": 0.7, "score": 0.6, "description": "How short"},
            ]
        })
